import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { SESSION_COOKIE_NAME, verifySessionToken } from "@/lib/auth";

const AUTH_REQUIRED_PREFIXES = ["/dashboard", "/queue", "/tractor", "/office", "/admin"];
const ADMIN_ONLY_PREFIXES = ["/tractor", "/office", "/admin"];

export async function proxy(req: NextRequest) {
  const { pathname } = req.nextUrl;

  if (pathname.startsWith("/api")) return NextResponse.next();

  const token = req.cookies.get(SESSION_COOKIE_NAME)?.value;
  const isAuthRequired = AUTH_REQUIRED_PREFIXES.some((p) => pathname === p || pathname.startsWith(p + "/"));

  // Redirect logged-in users away from home, login, register
  if (pathname === "/" || pathname === "/login" || pathname === "/register") {
    if (token) {
      try {
        const session = await verifySessionToken(token);
        const url = req.nextUrl.clone();
        url.pathname = session.role === "ADMIN" ? "/admin" : "/dashboard";
        url.search = "";
        return NextResponse.redirect(url);
      } catch {
        // Invalid token — let them through
      }
    }
    return NextResponse.next();
  }

  if (!isAuthRequired) return NextResponse.next();

  if (!token) return redirectToLogin(req);

  try {
    const session = await verifySessionToken(token);
    const isAdminRoute = ADMIN_ONLY_PREFIXES.some((p) => pathname === p || pathname.startsWith(p + "/"));
    if (isAdminRoute && session.role !== "ADMIN") {
      const url = req.nextUrl.clone();
      url.pathname = "/dashboard";
      url.search = "";
      return NextResponse.redirect(url);
    }
    return NextResponse.next();
  } catch {
    return redirectToLogin(req);
  }
}

function redirectToLogin(req: NextRequest) {
  const url = req.nextUrl.clone();
  url.pathname = "/login";
  url.searchParams.set("next", req.nextUrl.pathname);
  return NextResponse.redirect(url);
}

export const config = {
  matcher: ["/((?!_next/static|_next/image|favicon.ico).*)"],
};

export const runtime = "nodejs";

export async function GET() {
  return Response.json({ status: "ok" });
}

